#include<bits/stdc++.h>
using namespace std;
struct student{
	char name[15];
	int chinese,math,english;
	int total;
}a[1100];

int n;
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%s",a[i].name);
		scanf("%d%d%d",&(a[i].chinese),&(a[i].math),&(a[i].english));
		a[i].total=a[i].chinese+a[i].math+a[i].english;
	}
	for(int i=n;i>=1;i--)
	{
		for(int j=1;j<=i;j++)
		{
			if(a[j].total<a[j+1].total)
			{
				swap(a[j],a[j+1]);
			}
		}
	}
	printf("%s %d %d %d\n",a[1].name,a[1].chinese,a[1].math,a[1].english);
	return 0;
}
